import\('playwright'\).then\(async \({ chromium }\) => {
  const browser = await chromium.launch\({ headless: true }\);

  // === 1단계: 서비스 워커 등록된 상태 시뮬레이션 ===
  console.log\('=== Phase 1: Register OLD service worker ==='\);
  const ctx1 = await browser.newContext\(\);
  const page1 = await ctx1.newPage\(\);
  await page1.goto\('http://localhost:3000/', { waitUntil: 'networkidle', timeout: 15000 }\);
  await page1.waitForTimeout\(2000\);

  // SW 등록 상태 확인
  const swCount = await page1.evaluate\(async \(\) => {
    const regs = await navigator.serviceWorker.getRegistrations\(\);
    return regs.length;
  }\);
  console.log\('Service workers registered:', swCount\);
  await ctx1.close\(\);

  // === 2단계: 새 페이지에서 /meetings 접속 \(실제 유저와 동일\) ===
  console.log\('\\\\n=== Phase 2: Fresh visit to /meetings ==='\);
  const ctx2 = await browser.newContext\(\);
  const page2 = await ctx2.newPage\(\);

  const errors = [];
  page2.on\('pageerror', err => errors.push\(err.message\)\);

  await page2.goto\('http://localhost:3000/meetings', { waitUntil: 'networkidle', timeout: 15000 }\);
  await page2.waitForTimeout\(3000\);

  // 한번 더 새로고침 \(SW 자폭 후 캐시 정리된 상태\)
  await page2.reload\({ waitUntil: 'networkidle', timeout: 15000 }\);
  await page2.waitForTimeout\(3000\);

  const bodyText = await page2.evaluate\(\(\) => document.body.innerText\);
  const hasHeader = bodyText.includes\('회의 목록'\);
  const hasCards = bodyText.includes\('우주 혼나는'\) || bodyText.includes\('로드맵'\) || bodyText.includes\('디자인 시스템'\);

  console.log\('Has header 회의 목록:', hasHeader\);
  console.log\('Has meeting cards:', hasCards\);
  console.log\('Page errors:', errors.length > 0 ? errors : 'NONE'\);
  console.log\('Content preview:', bodyText.substring\(0, 300\)\);

  // SW가 해제되었는지 확인
  const swCount2 = await page2.evaluate\(async \(\) => {
    const regs = await navigator.serviceWorker.getRegistrations\(\);
    return regs.length;
  }\);
  console.log\('\\\\nService workers after cleanup:', swCount2\);

  await page2.screenshot\({ path: '/tmp/meetings-final.png', fullPage: true }\);
  console.log\('Screenshot: /tmp/meetings-final.png'\);

  await browser.close\(\);
}\).catch\(e => console.error\('FAIL:', e.message\)\);
